<?php
/**
 * Block: Seção Áreas de Atuação (Carrossel Swiper)
 */

// 1. Configurações Gerais
include 'conf_gerais.php';

// 2. Campos Específicos
$titulo = get_sub_field('titulo');
$classe_extra = get_sub_field('classe');
$subtitulo = 'Áreas de atuação';

// 3. Query personalizada
$args = array(
    'post_type'      => 'areas-de-atuacao',
    'posts_per_page' => 8,
    'orderby'        => 'date',
    'order'          => 'DESC',
);
$query_areas = new WP_Query($args);

// 4. Link do archive
$archive_link = get_post_type_archive_link('areas-de-atuacao');
?>

<section class="secao-atuacoes <?php echo esc_attr($classe . ' ' . $classe_extra); ?>" style="<?php echo esc_attr($geraisCSS); ?>">
    <div class="container">

        <!-- Cabeçalho -->
        <div class="secao-atuacoes__header">
            <div class="secao-atuacoes__badge animate-on-scroll eff-fade-up">
                <svg width="30" height="26" viewBox="0 0 30 26" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
                  <rect width="30" height="26" fill="url(#pattern0_6136_123)"/>
                  <defs>
                  <pattern id="pattern0_6136_123" patternContentUnits="objectBoundingBox" width="1" height="1">
                  <use xlink:href="#image0_6136_123" transform="matrix(0.000558419 0 0 0.00064433 -0.0078823 0)"/>
                  </pattern>
                  <image id="image0_6136_123" width="1819" height="1552" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
                  </defs>
                </svg>

                <span><?php echo esc_html($subtitulo); ?></span>
            </div>

            <?php if ($titulo) : ?>
                <h2 class="secao-atuacoes__titulo animate-on-scroll eff-fade-up delay-100">
                    <?php echo wp_kses_post($titulo); ?>
                </h2>
            <?php endif; ?>
        </div>

        <!-- Swiper Slider -->
        <?php if ($query_areas->have_posts()) : ?>
            <div class="swiper swiper-atuacoes animate-on-scroll eff-fade-up delay-200">
                <div class="swiper-wrapper">
                    <?php while ($query_areas->have_posts()) : $query_areas->the_post(); ?>
                        <div class="swiper-slide">
                            <a href="<?php the_permalink(); ?>" class="card-atuacao" aria-label="Acessar conteúdo de <?php echo esc_attr(get_the_title()); ?>">
                                <div class="card-atuacao__imagem-bg" aria-hidden="true">
                                    <?php if (has_post_thumbnail()) : ?>
                                        <?php the_post_thumbnail('large', ['loading' => 'lazy', 'alt' => '']); ?>
                                    <?php endif; ?>
                                    <div class="card-atuacao__overlay"></div>
                                </div>
                                <div class="card-atuacao__conteudo">
                                    <h3 class="card-atuacao__titulo"><?php the_title(); ?></h3>
                                    <div class="card-atuacao__resumo">
                                        <?php echo wp_trim_words(get_the_excerpt(), 18, '...'); ?>
                                    </div>
                                </div>
                            </a>
                        </div>
                    <?php endwhile; ?>
                    <?php wp_reset_postdata(); ?>
                </div>

                <!-- Pagination Progressbar -->
                <div class="swiper-atuacoes__pagination-wrapper">
                    <div class="swiper-pagination swiper-atuacoes-pagination"></div>
                </div>
            </div>
        <?php endif; ?>

        <!-- Botão Ver Todos -->
        <?php if ($archive_link) : ?>
            <div class="secao-atuacoes__cta animate-on-scroll eff-fade-in delay-300">
                <a href="<?php echo esc_url($archive_link); ?>" class="btn">
                    Ver todos
                    <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" width="16" height="16">
                        <path d="M7 17L17 7M17 7H7M17 7V17" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/>
                    </svg>
                </a>
            </div>
        <?php endif; ?>

    </div>
</section>
